import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./AdminDashboard.css";

const AdminDashboard = () => {
  const navigate = useNavigate();
  const [products, setProducts] = useState([]);
  const [users, setUsers] = useState([]);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(false);
  const [activePage, setActivePage] = useState(""); // Tracks active page

  // ===== LOGOUT =====
  const logout = () => {
    localStorage.removeItem("adminToken");
    navigate("/admin/login");
  };

  // ===== FETCH FUNCTIONS =====
  const fetchProducts = async () => {
    setLoading(true);
    setActivePage("products");
    try {
      const res = await axios.get("http://localhost:5000/api/admin/products");
      setProducts(res.data);
    } catch (err) {
      console.error("Fetch products error:", err);
      setProducts([]);
    }
    setLoading(false);
  };

  const fetchUsers = async () => {
    setLoading(true);
    setActivePage("users");
    try {
      const res = await axios.get("http://localhost:5000/api/admin/users");
      setUsers(res.data);
    } catch (err) {
      console.error("Fetch users error:", err);
      setUsers([]);
    }
    setLoading(false);
  };

  const fetchOrders = async () => {
    setLoading(true);
    setActivePage("orders");
    try {
      const res = await axios.get("http://localhost:5000/api/admin/orders");
      setOrders(res.data);
    } catch (err) {
      console.error("Fetch orders error:", err);
      setOrders([]);
    }
    setLoading(false);
  };

  // ===== PRODUCT CRUD FUNCTIONS =====
  const [newProduct, setNewProduct] = useState({
    name: "",
    price: "",
    stock: 0,
    image_url: "",
    category: "",
  });

  const handleNewProductChange = (e) => {
    setNewProduct({ ...newProduct, [e.target.name]: e.target.value });
  };

  const addProduct = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post(
        "http://localhost:5000/api/admin/products",
        newProduct
      );
      alert(res.data.message || "Product added successfully");
      setNewProduct({
        name: "",
        price: "",
        stock: 50,
        image_url: "",
        category: "",
      });
      fetchProducts();
    } catch (err) {
      console.error(err);
      alert("Failed to add product");
    }
  };

  const deleteProduct = async (id) => {
    if (!window.confirm("Are you sure you want to delete this product?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/admin/products/${id}`);
      fetchProducts();
    } catch (err) {
      console.error(err);
      alert("Failed to delete product");
    }
  };

  const updateProduct = async (id) => {
    const updatedName = prompt("Enter new product name:");
    if (!updatedName) return;
    try {
      await axios.put(`http://localhost:5000/api/admin/products/${id}`, {
        name: updatedName,
      });
      fetchProducts();
    } catch (err) {
      console.error(err);
      alert("Failed to update product");
    }
  };

  // ===== PAGE COMPONENTS =====
  const ProductsPage = () => {
    if (loading) return <p>Loading products...</p>;
    if (!products.length) return <p>No products found.</p>;

    return (
      <>
        <h2>Products</h2>
        <form className="product-form" onSubmit={addProduct}>
          <input
            type="text"
            name="name"
            placeholder="Product Name"
            value={newProduct.name}
            onChange={handleNewProductChange}
            required
          />
          <input
            type="number"
            name="price"
            placeholder="Price"
            value={newProduct.price}
            onChange={handleNewProductChange}
            required
          />
          <input
            type="number"
            name="stock"
            placeholder="Stock"
            value={newProduct.stock}
            onChange={handleNewProductChange}
          />
          <input
            type="text"
            name="image_url"
            placeholder="Image URL"
            value={newProduct.image_url}
            onChange={handleNewProductChange}
          />
          <input
            type="text"
            name="category"
            placeholder="Category"
            value={newProduct.category}
            onChange={handleNewProductChange}
          />
          <button type="submit">Add Product</button>
        </form>

        <table className="admin-table">
          <thead>
            <tr>
              <th>ID</th>
              <th>Name</th>
              <th>Price</th>
              <th>Stock</th>
              <th>Category</th>
              <th>Image</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {products.map((p) => (
              <tr key={p.id}>
                <td>{p.id}</td>
                <td>{p.name}</td>
                <td>{p.price}</td>
                <td>{p.stock}</td>
                <td>{p.category}</td>
                <td>
                  {p.image_url && (
                    <img src={p.image_url} alt={p.name} width={50} />
                  )}
                </td>
                <td>
                  <button onClick={() => updateProduct(p.id)}>Edit</button>
                  <button onClick={() => deleteProduct(p.id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </>
    );
  };

  const UsersPage = () => {
    if (loading) return <p>Loading users...</p>;
    if (!users.length) return <p>No users found.</p>;

    return (
      <>
        <h2>Users</h2>
        <table className="admin-table">
          <thead>
            <tr>
              <th>ID</th>
              <th>Name</th>
              <th>Email</th>
              <th>Registered At</th>
            </tr>
          </thead>
          <tbody>
            {users.map((u) => (
              <tr key={u.id}>
                <td>{u.id}</td>
                <td>{u.full_name}</td>
                <td>{u.email}</td>
                <td>{u.registered_at || "-"}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </>
    );
  };

  const OrdersPage = () => {
    if (loading) return <p>Loading orders...</p>;
    if (!orders.length) return <p>No orders found.</p>;

    return (
      <>
        <h2>Orders</h2>
        <table className="admin-table">
          <thead>
            <tr>
              <th>ID</th>
              <th>Name</th>
              <th>Email</th>
              <th>Total (RM)</th>
              <th>Date</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody>
            {orders.map((o) => (
              <tr key={o.id}>
                <td>{o.id}</td>
                <td>{o.full_name}</td>
                <td>{o.email}</td>
                <td>{o.total_amount}</td>
                <td>{o.created_at}</td>
                <td>{o.payment_status}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </>
    );
  };

  return (
    <div className="admin-layout">
      {/* SIDEBAR */}
      <aside className="admin-sidebar">
        <h2 className="logo">ShopAdmin</h2>
        <nav>
          <button className="nav-link" onClick={fetchProducts}>
            Products
          </button>
          <button className="nav-link" onClick={fetchOrders}>
            Orders
          </button>
          <button className="nav-link" onClick={fetchUsers}>
            Users
          </button>
        </nav>
        <button className="logout-btn" onClick={logout}>
          Logout
        </button>
      </aside>

      {/* MAIN CONTENT */}
      <main className="admin-content">
        <header className="admin-header">
          <h1>Dashboard</h1>
        </header>

        <section className="admin-page">
          {activePage === "products" && <ProductsPage />}
          {activePage === "orders" && <OrdersPage />}
          {activePage === "users" && <UsersPage />}
          {!activePage && <p>Welcome to your admin dashboard</p>}
        </section>
      </main>
    </div>
  );
};

export default AdminDashboard;
